  const init={ownerDep:biz.ownerDep||"medium",[revField]:calib?((biz.recurringPct!=null&&biz.recurringPct!=="")?String(biz.recurringPct):"20"):(biz.revenueType||"mixed"),customerConc:(biz.customerConc!=null&&biz.customerConc!=="")?String(biz.customerConc):"33"};
