function CountUp({value,format,dur=850}){
  const target=typeof value==="number"&&isFinite(value)?value:0;
  const [disp,setDisp]=React.useState(0);
  const fromRef=React.useRef(0); const rafRef=React.useRef(0);
  React.useEffect(()=>{
    const from=fromRef.current, to=target;
    if(from===to){setDisp(to);return;}
    const start=performance.now();
    cancelAnimationFrame(rafRef.current);
    const step=(now)=>{ const t=Math.min(1,(now-start)/dur); const e=1-Math.pow(1-t,3);
      setDisp(from+(to-from)*e);
      if(t<1) rafRef.current=requestAnimationFrame(step); else { fromRef.current=to; setDisp(to); } };
    rafRef.current=requestAnimationFrame(step);
    return ()=>cancelAnimationFrame(rafRef.current);
  },[target,dur]);
  return <>{format?format(disp):Math.round(disp).toLocaleString()}</>;
}
